def rearrangeCharacters(s: str, target: str) -> int:
    count = 0
    for i in range(len(s)):
        if s[i] == target[0]:
            count += 1
            for j in range(1, len(target)):
                if s[i+j] == target[j]:
                    count += 1
                    break
    return count

